#include <bits/stdc++.h>
using namespace std;

int main(){
    int n, wmax;
    cin >> n >> wmax;

    int W[n + 1];
    int V[n + 1];

    // Using one-based indexing
    for(int i = 1; i <= n; i++) {
        cin >> W[i] >> V[i];
    }   

    // We will use 2-d array to store the solution 
    int dp[n + 1][wmax + 1];

    for(int i = 0; i <= n; i++) {
        dp[i][0] = 0; // Base case
    }
    for(int w = 0; w <= wmax; w++) {
        dp[0][w] = 0; // Base case
    }   

    for(int i = 1; i <= n; i++) {
        for(int w = 1; w <= wmax; w++) {
            if(w >= W[i]) { // Check if we can take the Wi weight
                dp[i][w] = max(V[i] + dp[i - 1][w - W[i]], dp[i - 1][w]);
            }
            else {
                dp[i][w] = dp[i - 1][w];
            }
        }
    }

    cout << dp[n][wmax] << "\n";

    return 0;
}

