def knapsack(n, wmax, W, V):
    dp = [[0] * (wmax + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for w in range(1, wmax + 1):
            if w >= W[i]:
                dp[i][w] = max(V[i] + dp[i - 1][w - W[i]], dp[i - 1][w])
            else:
                dp[i][w] = dp[i - 1][w]

    return dp[n][wmax]

if __name__ == "__main__":
    n, wmax = map(int, input().split())

