import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int wmax = sc.nextInt();

        int[] W = new int[n + 1];
        int[] V = new int[n + 1];

        // Using one-based indexing
        for (int i = 1; i <= n; i++) {
            W[i] = sc.nextInt();
            V[i] = sc.nextInt();
        }

        // We will use a 2D array to store the solution
        int[][] dp = new int[n + 1][wmax + 1];

        for (int i = 0; i <= n; i++) {
            dp[i][0] = 0; // Base case
        }
        for (int w = 0; w <= wmax; w++) {
            dp[0][w] = 0; // Base case
        }

        for (int i = 1; i <= n; i++) {
            for (int w = 1; w <= wmax; w++) {
                if (w >= W[i]) { // Check if we can take the Wi weight
                    dp[i][w] = Math.max(V[i] + dp[i - 1][w - W[i]], dp[i - 1][w]);
                } else {
                    dp[i][w] = dp[i - 1][w];
                }
            }
        }

        System.out.println(dp[n][wmax]);
    }
}
